 46→        }
 47→
 48→        if (
 49→            config.isEmailAddressLengthCheckEnabled && Warning.EmailAddressExceedsLengthLimit in emailAddress.warnings
 50→        ) {
 51→            parserError(TotalLengthExceeded)
 52→        }
 53→
 54→        if (config.isLocalPartLengthCheckEnabled && Warning.LocalPartExceedsLengthLimit in emailAddress.warnings) {
 55→            parserError(LocalPartLengthExceeded, position = input.lastIndexOf('@'))
 56→        }
 57→
 58→        if (
 59→            !config.isLocalPartRequiringQuotedStringAllowed && Warning.QuotedStringInLocalPart in emailAddress.warnings
 60→        ) {
 61→            parserError(LocalPartRequiresQuotedString, position = 0)
 62→        }
 63→
 64→        if (!config.isEmptyLocalPartAllowed && Warning.EmptyLocalPart in emailAddress.warnings) {
 65→            parserError(EmptyLocalPart, position = 1)
