 19→
 20→import org.jetbrains.annotations.Nullable;
 21→
 22→
 23→/**
 24→ * This class stores an RFC 822-like name, address, and comment,
 25→ * and provides methods to convert them to quoted strings.
 26→ */
 27→public class Rfc822Token {
 28→    @Nullable
 29→    private String mName, mAddress, mComment;
 30→
 31→    /**
 32→     * Creates a new Rfc822Token with the specified name, address,
 33→     * and comment.
 34→     */
 35→    public Rfc822Token(@Nullable String name, @Nullable String address, @Nullable String comment) {
 36→        mName = name;
 37→        mAddress = address;
 38→        mComment = comment;
 39→    }
 40→
 41→    /**
 42→     * Returns the name part.
 43→     */
 44→    @Nullable
 45→    public String getName() {
 46→        return mName;
 47→    }
 48→
 49→    /**
 50→     * Returns the address part.
 51→     */
 52→    @Nullable
 53→    public String getAddress() {
 54→        return mAddress;
 55→    }
 56→
 57→    /**
 58→     * Returns the comment part.
 59→     */
 60→    @Nullable
 61→    public String getComment() {
 62→        return mComment;
 63→    }
 64→
 65→    /**
 66→     * Changes the name to the specified name.
 67→     */
 68→    public void setName(@Nullable String name) {
 69→        mName = name;
 70→    }
 71→
 72→    /**
 73→     * Changes the address to the specified address.
 74→     */
 75→    public void setAddress(@Nullable String address) {
 76→        mAddress = address;
 77→    }
 78→
 79→    /**
 80→     * Changes the comment to the specified comment.
 81→     */
 82→    public void setComment(@Nullable String comment) {
 83→        mComment = comment;
 84→    }
 85→
 86→    /**
 87→     * Returns the name (with quoting added if necessary),
 88→     * the comment (in parentheses), and the address (in angle brackets).
 89→     * This should be suitable for inclusion in an RFC 822 address list.
 90→     */
 91→    public String toString() {
 92→        StringBuilder sb = new StringBuilder();
 93→
 94→        if (mName != null && mName.length() != 0) {
 95→            sb.append(quoteNameIfNecessary(mName));
 96→            sb.append(' ');
 97→        }
 98→
 99→        if (mComment != null && mComment.length() != 0) {
100→            sb.append('(');
101→            sb.append(quoteComment(mComment));
102→            sb.append(") ");
103→        }
104→
105→        if (mAddress != null && mAddress.length() != 0) {
106→            sb.append('<');
107→            sb.append(mAddress);
108→            sb.append('>');
109→        }
110→
111→        return sb.toString();
112→    }
113→
114→    /**
115→     * Returns the name, conservatively quoting it if there are any
116→     * characters that are likely to cause trouble outside of a
117→     * quoted string, or returning it literally if it seems safe.
118→     */
119→    public static String quoteNameIfNecessary(String name) {
120→        int len = name.length();
121→
122→        for (int i = 0; i < len; i++) {
123→            char c = name.charAt(i);
124→
125→            if (! ((c >= 'A' && c <= 'Z') ||
126→                    (c >= 'a' && c <= 'z') ||
127→                    (c == ' ') ||
128→                    (c >= '0' && c <= '9'))) {
129→                return '"' + quoteName(name) + '"';
130→            }
131→        }
132→
133→        return name;
134→    }
135→
136→    /**
137→     * Returns the name, with internal backslashes and quotation marks
138→     * preceded by backslashes.  The outer quote marks themselves are not
139→     * added by this method.
140→     */
141→    public static String quoteName(String name) {
142→        StringBuilder sb = new StringBuilder();
143→
144→        int len = name.length();
145→        for (int i = 0; i < len; i++) {
146→            char c = name.charAt(i);
147→
148→            if (c == '\\' || c == '"') {
149→                sb.append('\\');
150→            }
151→
152→            sb.append(c);
153→        }
154→
155→        return sb.toString();
156→    }
157→
158→    /**
159→     * Returns the comment, with internal backslashes and parentheses
160→     * preceded by backslashes.  The outer parentheses themselves are
161→     * not added by this method.
162→     */
163→    public static String quoteComment(String comment) {
164→        int len = comment.length();
165→        StringBuilder sb = new StringBuilder();
166→
167→        for (int i = 0; i < len; i++) {
168→            char c = comment.charAt(i);
169→
170→            if (c == '(' || c == ')' || c == '\\') {
171→                sb.append('\\');
172→            }
173→
174→            sb.append(c);
175→        }
176→
177→        return sb.toString();
178→    }
179→
180→    public int hashCode() {
181→        int result = 17;
182→        if (mName != null) result = 31 * result + mName.hashCode();
183→        if (mAddress != null) result = 31 * result + mAddress.hashCode();
184→        if (mComment != null) result = 31 * result + mComment.hashCode();
185→        return result;
186→    }
187→
188→    private static boolean stringEquals(String a, String b) {
189→        if (a == null) {
190→            return (b == null);
191→        } else {
192→            return (a.equals(b));
193→        }
194→    }
195→
196→    public boolean equals(@Nullable Object o) {
197→        if (!(o instanceof Rfc822Token)) {
198→            return false;
199→        }
200→        Rfc822Token other = (Rfc822Token) o;
201→        return (stringEquals(mName, other.mName) &&
202→                stringEquals(mAddress, other.mAddress) &&
203→                stringEquals(mComment, other.mComment));
204→    }
205→}
